    17→/// Summary statistics for cards in the workspace.
    18→pub struct CardStats {
    19→    pub total: usize,
    20→    pub by_state: HashMap<String, usize>,
    21→    pub avg_duration_s: Option<f64>,
    22→    pub success_rate_pct: Option<f64>,
    23→}
    24→
    25→/// Calculate statistics: count cards by state and compute average duration.
    26→pub fn calculate_stats(root: &Path) -> anyhow::Result<CardStats> {
    27→    let states = ["drafts", "pending", "running", "done", "failed", "merged"];
    28→    let mut by_state = HashMap::new();
    29→    let mut total = 0;
    30→    let mut durations = Vec::new();
    31→
    32→    for state in &states {
    33→        // Process root-level state directory
    34→        collect_state_stats(root, state, &mut by_state, &mut total, &mut durations)?;
    35→
    36→        // Process team-* directories
    37→        if let Ok(entries) = fs::read_dir(root) {
    38→            for entry in entries.flatten() {
    39→                let team_path = entry.path();
    40→                if team_path.is_dir() && entry.file_name().to_string_lossy().starts_with("team-") {
    41→                    collect_state_stats(
    42→                        &team_path,
    43→                        state,
    44→                        &mut by_state,
    45→                        &mut total,
    46→                        &mut durations,
    47→                    )?;
    48→                }
    49→            }
    50→        }
    51→    }
    52→
    53→    let avg_duration_s = if durations.is_empty() {
    54→        None
    55→    } else {
    56→        Some(durations.iter().sum::<f64>() / durations.len() as f64)
    57→    };
    58→
    59→    let success_rate_pct = {
    60→        let done = by_state.get("done").copied().unwrap_or(0);
    61→        let failed = by_state.get("failed").copied().unwrap_or(0);
    62→        if done + failed > 0 {
    63→            Some((done as f64 / (done + failed) as f64) * 100.0)
    64→        } else {
    65→            None
    66→        }
    67→    };
    68→
    69→    Ok(CardStats {
    70→        total,
    71→        by_state,
    72→        avg_duration_s,
    73→        success_rate_pct,
    74→    })
    75→}
