    77→fn collect_state_stats(
    78→    dir: &Path,
    79→    state: &str,
    80→    by_state: &mut HashMap<String, usize>,
    81→    total: &mut usize,
    82→    durations: &mut Vec<f64>,
    83→) -> anyhow::Result<()> {
    84→    let state_dir = dir.join(state);
    85→    if !state_dir.exists() {
    86→        return Ok(());
    87→    }
    88→
    89→    let Ok(entries) = fs::read_dir(&state_dir) else {
    90→        return Ok(());
    91→    };
    92→
    93→    for entry in entries.flatten() {
    94→        let path = entry.path();
    95→        if path.is_dir()
    96→            && path
    97→                .extension()
    98→                .is_some_and(|e| e == "bop" || e == "jobcard")
    99→        {
   100→            if let Ok(meta) = bop_core::read_meta(&path) {
   101→                *by_state.entry(state.to_string()).or_insert(0) += 1;
   102→                *total += 1;
   103→
   104→                // Collect duration from last run if available
   105→                if let Some(last_run) = meta.runs.last() {
   106→                    if let Some(dur) = last_run.duration_s {
   107→                        durations.push(dur as f64);
   108→                    }
   109→                }
   110→            }
   111→        }
   112→    }
   113→
   114→    Ok(())
   115→}
