   123→        // Also check team-* directories
   124→        if let Ok(entries) = fs::read_dir(root) {
   125→            let mut team_dirs: Vec<_> = entries
   126→                .flatten()
   127→                .filter(|e| {
   128→                    let name = e.file_name();
   129→                    let s = name.to_string_lossy();
   130→                    e.path().is_dir() && s.starts_with("team-")
   131→                })
   132→                .collect();
   133→            team_dirs.sort_by_key(|e| e.file_name());
