   144→        if i < states.len() - 1 {
   145→            println!("{}{}{}", DIM, "─".repeat(80), RESET);
   146→        }
   147→    }
   148→    // Display summary statistics
   149→    println!("{}{}{}", DIM, "─".repeat(80), RESET);
   150→    let stats = calculate_stats(root)?;
   151→    print_summary(&stats);
   152→
   153→    Ok(())
   154→}
