     8→pub fn command_available(name: &str) -> bool {
     9→    // Try system PATH first
    10→    if StdCommand::new(name)
    11→        .arg("--version")
    12→        .output()
    13→        .map(|o| o.status.success())
    14→        .unwrap_or(false)
    15→    {
    16→        return true;
    17→    }
    18→    // Try well-known user-local paths
    19→    let home = std::env::var("HOME").unwrap_or_default();
    20→    for dir in [
    21→        format!("{home}/.local/bin"),
    22→        format!("{home}/.cargo/bin"),
    23→        "/opt/homebrew/bin".to_string(),
    24→    ] {
    25→        let full = format!("{dir}/{name}");
    26→        if StdCommand::new(&full)
    27→            .arg("--version")
    28→            .output()
    29→            .map(|o| o.status.success())
    30→            .unwrap_or(false)
    31→        {
    32→            return true;
    33→        }
    34→    }
    35→    false
    36→}
