   475→/// Detect terminal width via ioctl, COLUMNS env, or fallback to 100.
   476→/// Works inside Zellij panes, tmux, and normal terminals.
   477→fn term_width() -> usize {
   478→    // 1. Try ioctl TIOCGWINSZ (works in Zellij panes, tmux, etc.)
   479→    #[cfg(unix)]
   480→    {
   481→        use std::mem::MaybeUninit;
   482→        #[repr(C)]
   483→        struct Winsize {
   484→            ws_row: u16,
   485→            ws_col: u16,
   486→            ws_xpixel: u16,
   487→            ws_ypixel: u16,
   488→        }
   489→        unsafe {
   490→            let mut ws = MaybeUninit::<Winsize>::uninit();
   491→            // TIOCGWINSZ = 0x40087468 on macOS, 0x5413 on Linux
   492→            #[cfg(target_os = "macos")]
   493→            let request = 0x40087468u64;
   494→            #[cfg(target_os = "linux")]
   495→            let request = 0x5413u64;
   496→            if libc_ioctl(1, request, ws.as_mut_ptr() as *mut u8) == 0 {
   497→                let ws = ws.assume_init();
   498→                if ws.ws_col > 0 {
   499→                    return ws.ws_col as usize;
   500→                }
   501→            }
   502→        }
   503→    }
   504→    // 2. Fallback to COLUMNS env
   505→    std::env::var("COLUMNS")
   506→        .ok()
   507→        .and_then(|s| s.parse().ok())
   508→        .unwrap_or(100)
   509→}
   510→
   511→#[cfg(unix)]
   512→unsafe fn libc_ioctl(fd: i32, request: u64, arg: *mut u8) -> i32 {
   513→    extern "C" {
   514→        fn ioctl(fd: i32, request: u64, ...) -> i32;
   515→    }
   516→    ioctl(fd, request, arg)
   517→}
