   105→/// Cluster bars: gap > 30 min = new cluster.
   106→fn cluster(bars: &[Bar]) -> Vec<Vec<usize>> {
   107→    if bars.is_empty() {
   108→        return Vec::new();
   109→    }
   110→    let mut clusters: Vec<Vec<usize>> = vec![vec![0]];
   111→    for i in 1..bars.len() {
   112→        let prev_end = bars[clusters.last().unwrap().iter().copied().fold(0, |best, j| {
   113→            if bars[j].end > bars[best].end {
   114→                j
   115→            } else {
   116→                best
   117→            }
   118→        })]
   119→        .end;
   120→        if (bars[i].start - prev_end).num_seconds() > 1800 {
   121→            clusters.push(vec![i]);
   122→        } else {
   123→            clusters.last_mut().unwrap().push(i);
   124→        }
   125→    }
   126→    clusters
   127→}
