   137→// ── ANSI terminal rendering ─────────────────────────────────────────────────
   138→
   139→fn render_ansi(bars: &[Bar], term_width: usize) {
   140→    let clusters = cluster(bars);
   141→    let label_width = 24_usize;
   142→    let dur_width = 7_usize;
   143→    // bar_cols = total width - label - " │ " (3) - " " (1) - dur_label - " " (1)
   144→    let bar_cols = term_width
   145→        .saturating_sub(label_width + 3 + dur_width + 2)
   146→        .max(20);
   147→
   148→    // Header
   149→    println!(
   150→        "{}bop · agent timeline{} {} — {} runs{}",
   151→        BOLD,
   152→        RESET,
   153→        DIM,
   154→        bars.len(),
   155→        RESET
   156→    );
   157→    println!();
   158→
   159→    for indices in &clusters {
   160→        let c_min = indices.iter().map(|&i| bars[i].start).min().unwrap();
   161→        let c_max = indices.iter().map(|&i| bars[i].end).max().unwrap();
   162→        let c_span = (c_max - c_min).num_seconds().max(1) as f64;
   163→
   164→        // Cluster header
   165→        println!(
   166→            "{}{} — {} · {} runs{}",
   167→            DIM,
   168→            c_min.format("%b %d, %H:%M"),
   169→            c_max.format("%H:%M"),
   170→            indices.len(),
   171→            RESET,
   172→        );
   173→
   174→        // Time axis
   175→        let mut axis = String::with_capacity(label_width + 3 + bar_cols);
   176→        for _ in 0..label_width {
   177→            axis.push(' ');
   178→        }
   179→        axis.push_str(" │ ");
   180→
   181→        // Place time labels on the axis
   182→        let mut axis_chars: Vec<char> = vec![' '; bar_cols];
   183→        // We'll place a few evenly-spaced time markers
   184→        let n_marks = (bar_cols / 15).clamp(2, 8);
   185→        for m in 0..n_marks {
   186→            let frac = m as f64 / (n_marks - 1).max(1) as f64;
   187→            let col = (frac * (bar_cols - 5) as f64) as usize;
   188→            let t = c_min + Duration::milliseconds((frac * c_span * 1000.0) as i64);
   189→            let label = t.format("%H:%M").to_string();
   190→            for (j, ch) in label.chars().enumerate() {
   191→                if col + j < bar_cols {
   192→                    axis_chars[col + j] = ch;
   193→                }
   194→            }
   195→        }
   196→        let axis_str: String = axis_chars.into_iter().collect();
   197→        println!("{}{}{}{}", axis, DIM, axis_str, RESET);
   198→
   199→        // Separator
   200→        let mut sep = String::with_capacity(label_width + 3 + bar_cols);
   201→        for _ in 0..label_width {
   202→            sep.push(' ');
   203→        }
   204→        sep.push_str(" ├─");
   205→        for _ in 0..bar_cols {
   206→            sep.push('─');
   207→        }
   208→        println!("{}{}{}", DIM, sep, RESET);
   209→
   210→        // Bars
   211→        for &i in indices {
   212→            let b = &bars[i];
   213→
   214→            // Label: glyph + truncated id
   215→            let mut label = String::with_capacity(label_width);
   216→            if !b.glyph.is_empty() {
   217→                label.push_str(&b.glyph);
   218→                label.push(' ');
   219→            }
   220→            let id_budget = label_width.saturating_sub(label.chars().count());
   221→            let truncated: String = b.id.chars().take(id_budget).collect();
   222→            label.push_str(&truncated);
   223→            // Pad to label_width (by char count)
   224→            let pad = label_width.saturating_sub(label.chars().count());
   225→            for _ in 0..pad {
   226→                label.push(' ');
   227→            }
   228→
   229→            // Bar position
   230→            let start_frac = (b.start - c_min).num_milliseconds() as f64 / (c_span * 1000.0);
   231→            let end_frac = (b.end - c_min).num_milliseconds() as f64 / (c_span * 1000.0);
   232→            let col_start = (start_frac * bar_cols as f64).round() as usize;
   233→            let col_end = ((end_frac * bar_cols as f64).round() as usize).max(col_start + 1);
   234→            let col_end = col_end.min(bar_cols);
   235→
   236→            let color = state_ansi(b.state.as_str());
   237→            let bg = state_ansi_bg(b.state.as_str());
   238→
   239→            // Build the bar line
   240→            let mut bar_line = String::with_capacity(bar_cols + 32);
   241→            // Leading space
   242→            for _ in 0..col_start {
   243→                bar_line.push(' ');
   244→            }
   245→            // Filled block using ▓ with background color
   246→            bar_line.push_str(bg);
   247→            bar_line.push_str(color);
   248→            for _ in col_start..col_end {
   249→                bar_line.push('▓');
   250→            }
   251→            bar_line.push_str(RESET);
