    61→pub fn copy_dir_all(src: &Path, dst: &Path) -> anyhow::Result<()> {
    62→    fs::create_dir_all(dst)?;
    63→    for entry in WalkDir::new(src).min_depth(1) {
    64→        let entry = entry?;
    65→        let rel = entry.path().strip_prefix(src)?;
    66→        let target = dst.join(rel);
    67→        if entry.file_type().is_dir() {
    68→            fs::create_dir_all(&target)?;
    69→        } else if entry.file_type().is_file() {
    70→            if let Some(parent) = target.parent() {
    71→                fs::create_dir_all(parent)?;
    72→            }
    73→            fs::copy(entry.path(), &target)?;
    74→        }
    75→    }
    76→    Ok(())
    77→}
