   156→/// Format duration in human-readable form (e.g., "4m32s" or "45s").
   157→fn format_duration(seconds: f64) -> String {
   158→    if seconds >= 60.0 {
   159→        let mins = (seconds / 60.0).floor() as u64;
   160→        let secs = (seconds % 60.0).round() as u64;
   161→        if secs > 0 {
   162→            format!("{}m{}s", mins, secs)
   163→        } else {
   164→            format!("{}m", mins)
   165→        }
   166→    } else {
   167→        format!("{}s", seconds.round() as u64)
   168→    }
   169→}
   170→
   171→/// Display summary statistics line.
   172→fn print_summary(stats: &CardStats) {
   173→    let mut parts = vec![format!("{} total", stats.total)];
   174→
   175→    // Add key state counts
   176→    for state in ["running", "done", "failed", "pending"] {
   177→        if let Some(&count) = stats.by_state.get(state) {
   178→            if count > 0 {
   179→                parts.push(format!("{} {}", count, state));
   180→            }
   181→        }
   182→    }
   183→
   184→    // Add average duration if available
   185→    if let Some(avg) = stats.avg_duration_s {
   186→        parts.push(format!("avg {}", format_duration(avg)));
   187→    }
   188→
   189→    // Add success rate if available
   190→    if let Some(rate) = stats.success_rate_pct {
   191→        parts.push(format!("success rate {}%", rate.round() as u64));
   192→    }
   193→
   194→    println!("{}", parts.join(" · "));
   195→}
