    21→/// Summary statistics for cards in the workspace.
    22→pub struct CardStats {
    23→    pub total: usize,
    24→    pub by_state: HashMap<String, usize>,
    25→    pub avg_duration_s: Option<f64>,
    26→    pub success_rate_pct: Option<f64>,
    27→}
    28→
    29→/// Calculate statistics: count cards by state and compute average duration.
    30→pub fn calculate_stats(root: &Path) -> anyhow::Result<CardStats> {
    31→    let states = ["drafts", "pending", "running", "done", "failed", "merged"];
    32→    let mut by_state = HashMap::new();
    33→    let mut total = 0;
    34→    let mut durations = Vec::new();
    35→
    36→    for state in &states {
    37→        // Process root-level state directory
    38→        collect_state_stats(root, state, &mut by_state, &mut total, &mut durations)?;
    39→
    40→        // Process team-* directories
    41→        if let Ok(entries) = fs::read_dir(root) {
    42→            for entry in entries.flatten() {
    43→                let team_path = entry.path();
    44→                if team_path.is_dir() && entry.file_name().to_string_lossy().starts_with("team-") {
    45→                    collect_state_stats(
    46→                        &team_path,
    47→                        state,
    48→                        &mut by_state,
    49→                        &mut total,
    50→                        &mut durations,
    51→                    )?;
    52→                }
    53→            }
    54→        }
    55→    }
    56→
    57→    let avg_duration_s = if durations.is_empty() {
    58→        None
    59→    } else {
    60→        Some(durations.iter().sum::<f64>() / durations.len() as f64)
    61→    };
    62→
    63→    let success_rate_pct = {
    64→        let done = by_state.get("done").copied().unwrap_or(0);
    65→        let failed = by_state.get("failed").copied().unwrap_or(0);
    66→        if done + failed > 0 {
    67→            Some((done as f64 / (done + failed) as f64) * 100.0)
    68→        } else {
    69→            None
    70→        }
    71→    };
    72→
    73→    Ok(CardStats {
    74→        total,
    75→        by_state,
    76→        avg_duration_s,
    77→        success_rate_pct,
    78→    })
    79→}
    80→
    81→fn collect_state_stats(
    82→    dir: &Path,
    83→    state: &str,
    84→    by_state: &mut HashMap<String, usize>,
    85→    total: &mut usize,
    86→    durations: &mut Vec<f64>,
    87→) -> anyhow::Result<()> {
    88→    let state_dir = dir.join(state);
    89→    if !state_dir.exists() {
    90→        return Ok(());
    91→    }
    92→
    93→    let Ok(entries) = fs::read_dir(&state_dir) else {
    94→        return Ok(());
    95→    };
    96→
    97→    for entry in entries.flatten() {
    98→        let path = entry.path();
    99→        if path.is_dir()
   100→            && path
   101→                .extension()
   102→                .is_some_and(|e| e == "bop" || e == "jobcard")
   103→        {
   104→            if let Ok(meta) = bop_core::read_meta(&path) {
   105→                *by_state.entry(state.to_string()).or_insert(0) += 1;
   106→                *total += 1;
   107→
   108→                // Collect duration from last run if available
   109→                if let Some(last_run) = meta.runs.last() {
   110→                    if let Some(dur) = last_run.duration_s {
   111→                        durations.push(dur as f64);
   112→                    }
   113→                }
   114→            }
   115→        }
   116→    }
   117→
   118→    Ok(())
   119→}
