   211→                    "[list_cards_watch] failed to watch {}: {}",
   212→                    watch_dir.display(),
   213→                    e
   214→                );
   215→            }
   216→        }
   217→
   218→        for res in std_rx {
   219→            match res {
   220→                Ok(events) => {
   221→                    // Filter to only .bop directory events
   222→                    let relevant = events.iter().any(|e| {
   223→                        e.path.extension().and_then(|s| s.to_str()) == Some("bop")
   224→                            && matches!(
   225→                                e.kind,
   226→                                DebouncedEventKind::Any | DebouncedEventKind::AnyContinuous
