   125→/// Detect terminal width via ioctl, COLUMNS env, or fallback to 100.
   126→/// Works inside Zellij panes, tmux, and normal terminals.
   127→pub fn term_width() -> usize {
   128→    // 1. Try ioctl TIOCGWINSZ (works in Zellij panes, tmux, etc.)
   129→    #[cfg(unix)]
   130→    {
   131→        use std::mem::MaybeUninit;
   132→        #[repr(C)]
   133→        struct Winsize {
   134→            ws_row: u16,
   135→            ws_col: u16,
   136→            ws_xpixel: u16,
   137→            ws_ypixel: u16,
   138→        }
   139→        unsafe {
   140→            let mut ws = MaybeUninit::<Winsize>::uninit();
   141→            // TIOCGWINSZ = 0x40087468 on macOS, 0x5413 on Linux
   142→            #[cfg(target_os = "macos")]
   143→            let request = 0x40087468u64;
   144→            #[cfg(target_os = "linux")]
   145→            let request = 0x5413u64;
   146→            if libc_ioctl(1, request, ws.as_mut_ptr() as *mut u8) == 0 {
   147→                let ws = ws.assume_init();
   148→                if ws.ws_col > 0 {
   149→                    return ws.ws_col as usize;
   150→                }
   151→            }
   152→        }
   153→    }
   154→    // 2. Fallback to COLUMNS env
   155→    std::env::var("COLUMNS")
   156→        .ok()
   157→        .and_then(|s| s.parse().ok())
   158→        .unwrap_or(100)
   159→}
