   161→#[cfg(unix)]
   162→unsafe fn libc_ioctl(fd: i32, request: u64, arg: *mut u8) -> i32 {
   163→    extern "C" {
   164→        fn ioctl(fd: i32, request: u64, ...) -> i32;
   165→    }
   166→    ioctl(fd, request, arg)
   167→}
