   403→/// Format duration in human-readable form (e.g., "4m32s" or "45s").
   404→fn format_duration(seconds: f64) -> String {
   405→    if seconds >= 60.0 {
   406→        let mins = (seconds / 60.0).floor() as u64;
   407→        let secs = (seconds % 60.0).round() as u64;
   408→        if secs > 0 {
   409→            format!("{}m{}s", mins, secs)
   410→        } else {
   411→            format!("{}m", mins)
   412→        }
   413→    } else {
   414→        format!("{}s", seconds.round() as u64)
   415→    }
   416→}
