   162→/// Count how many lines will be printed by list_cards() for cursor positioning.
   163→fn count_display_lines(root: &Path, state_filter: &str) -> anyhow::Result<usize> {
   164→    let states = resolve_states(state_filter);
   165→    let mut line_count = 0;
   166→
   167→    for (i, state) in states.iter().enumerate() {
   168→        // Count root-level state group lines
   169→        line_count += count_state_group_lines(root, state)?;
   170→
   171→        // Count team-* directories
   172→        if let Ok(entries) = fs::read_dir(root) {
   173→            let mut team_dirs: Vec<_> = entries
   174→                .flatten()
   175→                .filter(|e| {
   176→                    let name = e.file_name();
   177→                    let s = name.to_string_lossy();
   178→                    e.path().is_dir() && s.starts_with("team-")
   179→                })
   180→                .collect();
   181→            team_dirs.sort_by_key(|e| e.file_name());
   182→            for entry in team_dirs {
   183→                line_count += count_state_group_lines(&entry.path(), state)?;
   184→            }
   185→        }
   186→
   187→        // Add separator between state groups (but not after the last one)
   188→        if i < states.len() - 1 {
   189→            line_count += 1; // separator line
   190→        }
   191→    }
   192→
   193→    // Final separator and summary
   194→    line_count += 1; // separator before summary
   195→    line_count += 1; // summary line
   196→
   197→    Ok(line_count)
   198→}
