   237→pub async fn list_cards_watch(root: &Path, state_filter: &str) -> anyhow::Result<()> {
   238→    // Collect all state directories to watch
   239→    let states = ["drafts", "pending", "running", "done", "failed", "merged"];
   240→    let mut watch_dirs = Vec::new();
   241→
   242→    // Add root-level state directories
   243→    for state in &states {
   244→        let state_dir = root.join(state);
   245→        if state_dir.exists() {
   246→            watch_dirs.push(state_dir);
   247→        }
   248→    }
   249→
   250→    // Add team-* state directories
   251→    if let Ok(entries) = fs::read_dir(root) {
   252→        for entry in entries.flatten() {
   253→            let team_path = entry.path();
   254→            if team_path.is_dir() && entry.file_name().to_string_lossy().starts_with("team-") {
   255→                for state in &states {
   256→                    let state_dir = team_path.join(state);
   257→                    if state_dir.exists() {
   258→                        watch_dirs.push(state_dir);
   259→                    }
   260→                }
   261→            }
   262→        }
   263→    }
   264→
   265→    // Set up filesystem watcher with 100ms debounce
   266→    let (tx, mut rx) = tokio_mpsc::unbounded_channel();
   267→    let watch_dirs_clone = watch_dirs.clone();
   268→
   269→    std::thread::spawn(move || {
   270→        let (std_tx, std_rx) = std::sync::mpsc::channel();
   271→        let mut debouncer = match new_debouncer(Duration::from_millis(100), std_tx) {
   272→            Ok(d) => d,
