   404→/// Format duration in human-readable form (e.g., "4m32s" or "45s").
   405→fn format_duration(seconds: f64) -> String {
   406→    if seconds >= 60.0 {
   407→        let mins = (seconds / 60.0).floor() as u64;
   408→        let secs = (seconds % 60.0).round() as u64;
   409→        if secs > 0 {
   410→            format!("{}m{}s", mins, secs)
   411→        } else {
   412→            format!("{}m", mins)
   413→        }
   414→    } else {
   415→        format!("{}s", seconds.round() as u64)
   416→    }
   417→}
